import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm selects the next node based on a weighted combination of direct distance, inverse node centrality, and a measure of route variance to encourage varied paths and avoid node clustering.}
    """
    # Step 1: Direct distance attraction for unvisited nodes.
    direct_distances = {node: distance_matrix[current_node, node] for node in unvisited_nodes}

    # Step 2: Calculate node centrality to avoid congested nodes.
    centrality = {node: np.sum(distance_matrix[:, node]) for node in unvisited_nodes}

    # Step 3: Calculate route variance to promote varied routing.
    route_variance = {node: np.var([distance_matrix[current_node, n] for n in truck_nodes]) 
                      if len(truck_nodes) > 0 else 0 for node in unvisited_nodes}

    # Step 4: Compute a new score using different parameter settings.
    scores = {
        node: (0.2 * direct_distances[node] +
               0.5 * (1.0 / (centrality[node] + 1.e-5)) +
               0.3 * route_variance[node])
        for node in unvisited_nodes
    }

    # Step 5: Select the node with the highest score.
    next_node = min(scores, key=scores.get)

    return next_node
